// // This module decrements its value on each negative edge of the clock signal when the disable signal is inactive.
module top_module(
  input clk,
  input reset,
  input enable,
  output [3:0] count
);reg [3:0] count_reg;

  always @(posedge clk) begin
    if (reset) begin
      count_reg <= 4'b0;
    end
    else if (enable) begin
      count_reg <= count_reg + 1;
    end
  end

  assign count = count_reg;

endmodule
